import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import './SelectedWork.css';

const projects = [
  {
    id: 1,
    title: 'LuxeWear',
    year: '2025',
    category: 'Branding & Identity',
    slug: 'luxewear',
    image: 'https://framerusercontent.com/images/Rkv2Y35XqOtjHMDCogQD8Lzlr4o.jpg',
  },
  {
    id: 2,
    title: 'Pulse Media',
    year: '2024',
    category: 'Web Design',
    slug: 'pulse-media',
    image: 'https://framerusercontent.com/images/hpK2jiBaOZYg5CRERfR8Du1A4.jpg',
  },
  {
    id: 3,
    title: 'Zenith Finance',
    year: '2024',
    category: 'UI/UX Design',
    slug: 'zenith-finance',
    image: 'https://framerusercontent.com/images/XXuNfmUtvbIoDgOoziBdpthwU.jpg',
  },
  {
    id: 4,
    title: 'BoldTech',
    year: '2023',
    category: 'Web Design & Development',
    slug: 'boldtech',
    image: 'https://framerusercontent.com/images/i55vTTF0hVCC5GqlkA0XAW6ZSNI.jpg',
  },
  {
    id: 5,
    title: 'Velocity Motors',
    year: '2022',
    category: 'Motion & Visual Design',
    slug: 'velocity-motors',
    image: 'https://framerusercontent.com/images/rwxqhSPLCEUd9f042FJNbwEnA.jpg',
  },
  {
    id: 6,
    title: 'NovaFit',
    year: '2022',
    category: 'Branding & UI/UX',
    slug: 'novafit',
    image: 'https://framerusercontent.com/images/p3VFqTJkkbSJyG4gQML0VHVxLA.jpg',
  },
];

export default function SelectedWork() {
  const [hovered, setHovered] = useState(null);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });

  const handleMouseMove = (e) => {
    setMousePos({ x: e.clientX, y: e.clientY });
  };

  return (
    <section className="selected-work" onMouseMove={handleMouseMove}>
      <div className="container">
        <div className="work-header">
          <div>
            <p className="section-label">Selected Work</p>
            <h2 className="work-title">Explore how Scarlet has helped businesses<br />elevate their digital presence.</h2>
          </div>
          <Link to="/projects" className="arrow-link view-all">
            View all →
          </Link>
        </div>

        <div className="work-list">
          {projects.map((p, i) => (
            <Link
              to={`/projects`}
              key={p.id}
              className={`work-item ${hovered === i ? 'active' : ''}`}
              onMouseEnter={() => setHovered(i)}
              onMouseLeave={() => setHovered(null)}
            >
              <span className="work-num">0{i + 1}</span>
              <span className="work-name">{p.title}</span>
              <span className="work-cat">{p.category}</span>
              <span className="work-year">{p.year}</span>
              <span className="work-arrow">→</span>
            </Link>
          ))}
        </div>
      </div>

      {/* Floating image on hover */}
      {hovered !== null && (
        <div
          className="floating-image"
          style={{ left: mousePos.x + 30, top: mousePos.y - 100 }}
        >
          <img src={projects[hovered].image} alt={projects[hovered].title} />
        </div>
      )}
    </section>
  );
}
